export type AnimationType = 'fade' | 'fade-up' | 'fade-down' | 'fade-left' | 'fade-right';

// Bản đồ ánh xạ từ từ khóa Easing sang hàm Cubic-Bezier tương ứng
const EASING_MAP: Record<string, string> = {
  'linear': 'linear',
  'ease-in': 'cubic-bezier(0.42, 0, 1, 1)',
  'ease-out': 'cubic-bezier(0, 0, 0.58, 1)',
  'ease-in-out': 'cubic-bezier(0.42, 0, 0.58, 1)',
  'expo-in': 'cubic-bezier(0.7, 0, 0.84, 0)',
  'expo-out': 'cubic-bezier(0.16, 1, 0.3, 1)',
  'expo-in-out': 'cubic-bezier(0.87, 0, 0.13, 1)',
  'back-in': 'cubic-bezier(0.36, 0, 0.66, -0.56)',
  'back-out': 'cubic-bezier(0.34, 1.56, 0.64, 1)',
  'back-in-out': 'cubic-bezier(0.68, -0.6, 0.32, 1.6)'
};

export class SxAnimate extends HTMLElement {
  private static _observer: IntersectionObserver | null = null;

  static get observedAttributes() {
    return ['type', 'duration', 'delay', 'strength', 'easing', 'once'];
  }

  constructor() {
    super();
  }

  connectedCallback() {
    // Thiết lập các giá trị mặc định nếu Attribute trống
    if (!this.hasAttribute('type')) this.setAttribute('type', 'fade-up');
    if (!this.hasAttribute('duration')) this.setAttribute('duration', '300');
    if (!this.hasAttribute('delay')) this.setAttribute('delay', '0');
    if (!this.hasAttribute('strength')) this.setAttribute('strength', '100');
    if (!this.hasAttribute('easing')) this.setAttribute('easing', 'ease-in-out');
    if (!this.hasAttribute('once')) this.setAttribute('once', 'true');

    // Cập nhật các biến CSS động dựa trên Attributes hiện tại
    this._updateStyles();

    // Đăng ký vào hệ thống Observer dùng chung
    if (!SxAnimate._observer) {
      SxAnimate._initObserver();
    }
    SxAnimate._observer?.observe(this);
  }

  disconnectedCallback() {
    SxAnimate._observer?.unobserve(this);
  }

  attributeChangedCallback(name: string, oldValue: string, newValue: string) {
    if (oldValue !== newValue && this.isConnected) {
      this._updateStyles();
    }
  }

  // Hàm tính toán và đẩy biến CSS trực tiếp vào inline style của Element
  private _updateStyles() {
    const duration = parseFloat(this.getAttribute('duration') || '300');
    const delay = parseFloat(this.getAttribute('delay') || '0');
    const strength = parseFloat(this.getAttribute('strength') || '100');
    const easingKey = this.getAttribute('easing') || 'ease-in-out';
    
    // Tìm hàm transition bezier, nếu điền sai từ khóa tự động fallback về ease-in-out
    const easingValue = EASING_MAP[easingKey] || EASING_MAP['ease-in-out'];

    this.style.setProperty('--sx-duration', `${duration}ms`);
    this.style.setProperty('--sx-delay', `${delay}ms`);
    this.style.setProperty('--sx-strength-px', `${strength}px`);
    this.style.setProperty('--sx-easing', easingValue);
  }

  // Khởi tạo Intersection Observer thông minh
  private static _initObserver() {
    SxAnimate._observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          const target = entry.target as SxAnimate;
          const isOnce = target.getAttribute('once') !== 'false'; // Mặc định là true nếu không điền

          if (entry.isIntersecting) {
            // Kiểm tra tính năng group (kích hoạt lần lượt các phần tử con bên trong)
            if (target.hasAttribute('group')) {
              const children = target.children;
              const baseDelay = parseFloat(target.getAttribute('delay') || '0');
              const duration = parseFloat(target.getAttribute('duration') || '300');
              
              // Tự động tính toán rải delay đều cho từng phần tử con (stagger effect)
              Array.from(children).forEach((child, index) => {
                const element = child as HTMLElement;
                element.style.transition = `opacity ${duration}ms var(--sx-easing, ease-in-out), transform ${duration}ms var(--sx-easing, ease-in-out)`;
                element.style.transitionDelay = `${baseDelay + (index * 100)}ms`;
              });
            }

            target.classList.add('is-animated');
            target.dispatchEvent(new CustomEvent('animated', { bubbles: true }));

            // Nếu thiết lập once="true", gỡ bỏ theo dõi ngay lập tức để giải phóng CPU
            if (isOnce) {
              SxAnimate._observer?.unobserve(target);
            }
          } else {
            // Nếu once="false" và phần tử cuộn ra khỏi khung nhìn, reset lại trạng thái để chạy lại lần sau
            if (!isOnce) {
              target.classList.remove('is-animated');
            }
          }
        });
      },
      {
        root: null,
        rootMargin: '0px 0px -20px 0px', // Kích hoạt mượt mà trước khi chạm mép màn hình 20px
        threshold: 0.05
      }
    );
  }
}

if (!customElements.get('sx-animate')) {
  customElements.define('sx-animate', SxAnimate);
}